const webhookData = $('接收飞书消息').item.json.body;
const userText = webhookData.user_text;
const messageId = webhookData.message_id;
const chatId = webhookData.chat_id;
const senderOpenId = webhookData.sender_open_id;

const senderInfo = $('查询发送者信息').item.json;
const senderName = senderInfo.data?.user?.name || '未知用户';

const now = new Date();
const chinaOffset = 8 * 60 * 60 * 1000;
const chinaTime = new Date(now.getTime() + chinaOffset + now.getTimezoneOffset() * 60 * 1000);
const nowChinaStr = chinaTime.toISOString().replace('T', ' ').substring(0, 19);
const nowTimestamp = now.getTime();

const fieldsResponse = $input.item.json;
const fields = fieldsResponse.data?.items || [];

const readonlyTypes = [1001, 1002, 1003, 1004, 1005, 19, 20];

const typeMap = {
  1: '文本', 2: '数字', 3: '单选', 4: '多选',
  5: '日期时间', 7: '复选框', 11: '人员', 13: '电话',
  15: '超链接', 17: '附件', 18: '单向关联', 21: '双向关联',
  22: '地理位置', 23: '群组'
};

const personFieldNames = fields.filter(f => f.type === 11).map(f => f.field_name);
const dateFieldNames = fields.filter(f => f.type === 5).map(f => f.field_name);

const writableFields = fields.filter(f => !readonlyTypes.includes(f.type));

const fieldsDescription = writableFields.map(f => {
  const typeName = typeMap[f.type] || `未知(${f.type})`;
  let desc = `- ${f.field_name} (类型: ${typeName})`;
  if (f.type === 11) {
    desc += ` [当前提出人: ${senderName}]`;
  }
  if (f.type === 5) {
    desc += ` [若用户未提及日期，默认使用当前时间: ${nowChinaStr}，时间戳: ${nowTimestamp}]`;
  }
  if (f.description?.text) desc += ` [说明: ${f.description.text}]`;
  if (f.property?.options?.length > 0) {
    desc += ` [可选值: ${f.property.options.map(o => o.name).join('、')}]`;
  }
  return desc;
}).join('\n');

const fieldNameList = writableFields.map(f => f.field_name).join('、');

const prompt = `你是一个飞书多维表格记录填充助手。根据用户的需求描述，为多维表格生成一条新记录的字段值。

【提出人】${senderName}
【当前时间（中国时区）】${nowChinaStr}
【当前 Unix 毫秒时间戳】${nowTimestamp}

【用户需求】
${userText}

【表格可填写字段】
${fieldsDescription}

【输出要求】
1. 返回一个合法的 JSON 对象，key 是字段名，value 是对应的值
2. 只填写你能从需求中合理推断的字段，无法推断的字段不要包含在 JSON 中
3. 文本类型字段直接填字符串值
4. 单选类型字段必须从可选值中选择一个，用字符串填写
5. 多选类型字段用字符串数组填写，每个值必须从可选值中选择
6. 数字类型字段填数字
7. 日期时间类型字段填 Unix 毫秒时间戳（纯数字）。如果用户需求中没有明确提及日期，所有日期时间字段默认使用当前时间戳 ${nowTimestamp}
8. 复选框类型字段填 true 或 false
9. 人员类型字段填字符串 "SENDER"（后续系统会自动替换为实际人员 ID）
10. 可填写的字段名有：${fieldNameList}
11. 不要填写名为「AI需求说明」的字段，它会由另一个流程自动填充

【重要】只输出 JSON 对象，不要有任何其他文字、解释或 markdown 格式。`;

return {
  userText,
  prompt,
  message_id: messageId,
  chat_id: chatId,
  sender_open_id: senderOpenId,
  sender_name: senderName,
  person_field_names: personFieldNames,
  date_field_names: dateFieldNames,
  now_timestamp: nowTimestamp,
  tenant_access_token: $('获取飞书 Tenant Token').item.json.tenant_access_token
};

const aiContent = $json.choices?.[0]?.message?.content || '';

const jsonMatch = aiContent.match(/\{[\s\S]*\}/);
if (!jsonMatch) {
  throw new Error('AI 返回内容中未找到 JSON 对象: ' + aiContent);
}

const recordFields = JSON.parse(jsonMatch[0]);

const prevData = $('构建 AI Prompt').item.json;
const senderOpenId = prevData.sender_open_id;
const personFieldNames = prevData.person_field_names || [];
const dateFieldNames = prevData.date_field_names || [];
const nowTimestamp = prevData.now_timestamp;

for (const [key, value] of Object.entries(recordFields)) {
  if (personFieldNames.includes(key) && (!Array.isArray(value) || !value[0]?.id)) {
    recordFields[key] = [{ id: senderOpenId }];
  }
}

for (const [key, value] of Object.entries(recordFields)) {
  if (dateFieldNames.includes(key)) {
    const num = Number(value);
    if (!Number.isFinite(num) || num < 0) {
      recordFields[key] = nowTimestamp;
    } else {
      recordFields[key] = num;
    }
  }
}

return {
  recordFields,
  message_id: prevData.message_id,
  chat_id: prevData.chat_id,
  userText: prevData.userText,
  sender_name: prevData.sender_name,
  tenant_access_token: prevData.tenant_access_token
};

const prdContent = $json.choices?.[0]?.message?.content || '';

const prevData = $('解析填表结果并注入人员').item.json;
const recordFields = { ...prevData.recordFields };

recordFields['AI需求说明'] = prdContent;

return {
  recordFields,
  prdContent,
  message_id: prevData.message_id,
  chat_id: prevData.chat_id,
  userText: prevData.userText,
  sender_name: prevData.sender_name,
  tenant_access_token: prevData.tenant_access_token
};

const prevData = $('合并 PRD 到记录字段').item.json;
const createResult = $json;

const recordId = createResult.data?.record?.record_id || '未知';
const recordFields = prevData.recordFields;
const senderName = prevData.sender_name;

const bitableUrl = '{{BITABLE_BASE_URL}}{{BITABLE_APP_TOKEN}}?table={{BITABLE_TABLE_ID}}&view=veweQZFzEq';

// 日期时间戳格式化为可读字符串（中国时区）
function formatTimestamp(ts) {
  if (!ts || isNaN(Number(ts))) return String(ts);
  const d = new Date(Number(ts));
  const offset = 8 * 60 * 60 * 1000;
  const cst = new Date(d.getTime() + offset + d.getTimezoneOffset() * 60 * 1000);
  return cst.toISOString().replace('T', ' ').substring(0, 10);
}

// 提取部门信息
const deptRaw = recordFields['提出人.部门'];
let deptDisplay = '';
if (Array.isArray(deptRaw) && deptRaw.length > 0) {
  deptDisplay = deptRaw.join('、');
} else if (typeof deptRaw === 'string' && deptRaw) {
  deptDisplay = deptRaw;
}

// 跳过字段列表（仅跳过 AI 说明，部门单独处理）
const skipFields = ['AI需求说明', '提出人.部门'];

// 日期类字段名
const dateKeywords = ['日期', '时间'];

// 生成字段 fields 数组（两列布局）
const fieldEntries = [];
for (const [key, value] of Object.entries(recordFields)) {
  if (skipFields.includes(key)) continue;
  let displayValue;
  if (Array.isArray(value) && value[0]?.id) {
    displayValue = senderName;
  } else if (typeof value === 'number' && dateKeywords.some(k => key.includes(k))) {
    displayValue = formatTimestamp(value);
  } else if (typeof value === 'object') {
    displayValue = JSON.stringify(value);
  } else {
    displayValue = String(value);
  }
  fieldEntries.push({ key, displayValue });
}

// 每行两列显示字段
const fieldDivs = [];
for (let i = 0; i < fieldEntries.length; i += 2) {
  const left = fieldEntries[i];
  const right = fieldEntries[i + 1];
  const fields = [
    { is_short: true, text: { tag: 'lark_md', content: '**' + left.key + '**\n' + left.displayValue } }
  ];
  if (right) {
    fields.push({ is_short: true, text: { tag: 'lark_md', content: '**' + right.key + '**\n' + right.displayValue } });
  }
  fieldDivs.push({ tag: 'div', fields });
}

// 顶部 note 元素：部门信息
const noteElements = deptDisplay
  ? [{ tag: 'note', elements: [{ tag: 'plain_text', content: '🏢 所属部门：' + deptDisplay }] }]
  : [];

const cardContent = {
  config: { wide_screen_mode: true },
  header: {
    title: { tag: 'plain_text', content: '✅ 需求记录已创建' },
    template: 'green'
  },
  elements: [
    {
      tag: 'div',
      fields: [
        { is_short: true, text: { tag: 'lark_md', content: '**提出人**\n' + senderName } },
        { is_short: true, text: { tag: 'lark_md', content: '**记录 ID**\n' + recordId } }
      ]
    },
    ...noteElements,
    { tag: 'hr' },
    {
      tag: 'div',
      text: { tag: 'lark_md', content: '**📋 需求字段详情**' }
    },
    ...fieldDivs,
    { tag: 'hr' },
    {
      tag: 'div',
      text: { tag: 'lark_md', content: '**🤖 AI需求说明**\n已根据您的描述自动生成完整 PRD 文档，已写入多维表格对应字段。' }
    },
    { tag: 'hr' },
    {
      tag: 'action',
      actions: [
        {
          tag: 'button',
          text: { tag: 'plain_text', content: '📊 查看多维表格' },
          type: 'primary',
          url: bitableUrl
        }
      ]
    }
  ]
};

return {
  message_id: prevData.message_id,
  cardContent: JSON.stringify(cardContent),
  tenant_access_token: prevData.tenant_access_token
};
